```class Solution {
public:
    int findTheLongestSubstring(string s) {
        int n = s.size(), res = 0;
        vector<int> cnt(65, 0);
        unordered_map<int, int> mp;
        mp[0] = -1;
        int mask = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == 'a' || s[i] == 'e' || s[i] == 'i' || s[i] == 'o' || s[i] == 'u') {
                cnt[s[i] - 'a']++;
                if (cnt[s[i] - 'a'] % 2) mask ^= 1 << (s[i] - 'a');
                else mask ^= 1 << (s[i] - 'a');
            }
            if (mp.find(mask) != mp.end()) res = max(res, i - mp[mask]);
            else mp[mask] = i;
        }
        return res;
    }
};
